export class ForgotPasswordComponent implements OnInit {
  form!: UntypedFormGroup;
  loading = false;
  submitted = false;
  emailSent = false;

  constructor(
    private formBuilder: UntypedFormBuilder,
    private accountService: AccountService,
    private alertService: AlertService
  ) { }

  ngOnInit() {
    this.form = this.formBuilder.group({
      email: ['', [Validators.required, Validators.email]]
    });
  }

  get f() { return this.form.controls; }

  onSubmit() {
    this.submitted = true;
    this.alertService.clear();
    if (this.form.invalid) return;
    this.loading = true;
    this.accountService.forgotPassword(this.f['email'].value)
      .pipe(first())
      .subscribe({
        next: () => {
          this.alertService.success('Please check your email for password reset instructions', { id: 'forgot-password-alert' });
          this.emailSent = true;
        },
        error: (error: string) => {
          this.alertService.error(error, { id: 'forgot-password-alert' });
          this.loading = false;
        }
      });
  }
}
<h4 class="card-title mb-4">Forgot Password</h4>
<alert id="forgot-password-alert"></alert>
<div *ngIf="!emailSent">
  <p>Enter your email and we'll send you a link to reset your password.</p>
  <form [formGroup]="form" (ngSubmit)="onSubmit()">
    <div class="mb-3">
      <label class="form-label">Email</label>
      <input type="text" formControlName="email" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['email'].errors }" />
      <div *ngIf="submitted && f['email'].errors" class="invalid-feedback">
        <div *ngIf="f['email'].errors['required']">Email is required</div>
        <div *ngIf="f['email'].errors['email']">Email must be a valid email address</div>
      </div>
    </div>
    <div class="d-flex justify-content-between">
      <button [disabled]="loading" class="btn btn-primary">
        <span *ngIf="loading" class="spinner-border spinner-border-sm me-1"></span>
        Submit
      </button>
      <a routerLink="/account/login">Cancel</a>
    </div>
  </form>
</div>
